    var idx = s.indexOf('：');
    if (idx < 0) idx = s.indexOf(':');
    var lead = idx >= 0 ? s.slice(0, idx).trim() : '';
    var body = idx >= 0 ? s.slice(idx + 1).trim() : s;
    var paras = splitParas(body);
    if (!paras.length && body) paras = [body];
    return { lead: lead, paras: paras };
