  function inferRouteKey(stat) {
    var 命途 = safeObj(stat && stat['命途']);
    var 履历 = safeObj(stat && stat['履历']);
    var 主导 = 命途['主导'];
    if (主导) return ROUTE_MV[String(主导)] || 'route_qianlong';
    var 已锁 = Array.isArray(命途['已锁']) ? 命途['已锁'] : [];
    var 标签 = Array.isArray(命途['标签']) ? 命途['标签'] : [];
    if (已锁.indexOf('早隐') >= 0) return 'route_shanlin';
    if (已锁.indexOf('勤王缺席') >= 0) return 'route_pangguan';
    if (标签.indexOf('拒禅') >= 0) return 'route_weiguo';
    if (履历含(履历, '拒征辟') || 履历含(履历, '平原隐居')) return 'route_shanlin';
    if (履历含(履历, '司马使者')) return 'route_pangguan';
    if (履历含(履历, '拒废帝') || 履历含(履历, '剑阁撤军')) return 'route_yishu';
    return 'route_qianlong';
  }

  function phaseUnionHas(ph, eventId) {
    var hit = false;
    (ph['通用'] || []).forEach(function (x) {
      if (x === eventId) hit = true;
    });
    Object.keys(ph.routes || {}).forEach(function (rk) {
      (ph.routes[rk] || []).forEach(function (x) {
        if (x === eventId) hit = true;
      });
    });
    return hit;
  }

  function phaseAllowsEvent(stat, eventId) {
    var pools = Array.isArray(DWF_PHASE_POOLS) ? DWF_PHASE_POOLS : [];
    var pooledIds = Array.isArray(DWF_POOLED_EVENT_IDS) ? DWF_POOLED_EVENT_IDS : [];
    var pooledSet = {};
    for (var pi = 0; pi < pooledIds.length; pi++) pooledSet[pooledIds[pi]] = true;
    if (!pools.length || !eventId) return true;
    var trip = Number(safeObj(stat && stat['世界与剧情'])['行程']) || 1;
    var ph = null;
    for (var i = 0; i < pools.length; i++) {
      var p = pools[i];
      if (trip >= p.lo && trip <= p.hi) {
        ph = p;
        break;
      }
    }
    if (!ph) return true;
    if (pooledIds.length && pooledSet[eventId] && !phaseUnionHas(ph, eventId)) return false;
    if (!phaseUnionHas(ph, eventId)) return true;
    var route = inferRouteKey(stat);
    var allowed = {};
    (ph['通用'] || []).forEach(function (x) {
      allowed[x] = true;
    });
    ((ph.routes && ph.routes[route]) || []).forEach(function (x) {
      allowed[x] = true;
    });
    return !!allowed[eventId];
  }

  function computeJiyiFromCatalog(stat) {
    var catalog = Array.isArray(DWF_JIYI_CATALOG) ? DWF_JIYI_CATALOG : [];
    if (!catalog.length) return { 津渡: {}, 支汊: {} };
    var world = (stat && stat['世界与剧情']) || {};
    var trip = Number(world['行程']) || 1;
    var 履历 = safeObj(stat && stat['履历']);
    var 命途 = safeObj(stat && stat['命途']);
    var 鼎革 = safeObj(stat && stat['鼎革纪']);
    var taskLog = safeObj(stat && stat['任务录']);
    var abandoned = safeObj(taskLog['已放弃']);
    var matched = [];
    catalog.forEach(function (ev) {
      if (trip < (Number(ev['开启行程']) || 1) || trip > (Number(ev['截止行程']) || 288)) return;
      if (履历含(履历, ev.id)) return;
      if (hasCurrentTask(stat, ev.id)) return;
      if (abandoned[ev.id]) return;
      if (!命途满足(ev, 履历, 命途, 鼎革)) return;
      if (!phaseAllowsEvent(stat, ev.id)) return;
      matched.push(ev);
    });
    var mutexWin = {};
    var finalList = [];
    matched.forEach(function (ev) {
      var g = ev['互斥组'];
      if (!g) {
        finalList.push(ev);
        return;
      }
      if (!mutexWin[g] || betterEvent(ev, mutexWin[g])) mutexWin[g] = ev;
    });
    Object.keys(mutexWin).forEach(function (g) {
      finalList.push(mutexWin[g]);
    });
    var 津渡 = {};
    var 支汊 = {};
    finalList.forEach(function (ev) {
      var body = {
        因由: ev['因由'] || '',
        火急: ev['火急'] || 2,
        相关人物: ev['相关人物'] || '',
        建议地点: ev['建议地点'] || '',
        目标: ev['目标'] || {},
        开启行程: ev['开启行程'],
        截止行程: ev['截止行程'],
        卡片标签: ev['卡片标签'] || [],
      };
      if (ev['类型'] === '津渡') 津渡[ev.id] = body;
      else 支汊[ev.id] = body;
    });
    return { 津渡: 津渡, 支汊: 支汊 };
  }

  function resolveJiyiPools(stat) {
    var fx = safeObj(stat && stat['风闻录']);
    var jiyi = safeObj(fx['机宜']);
    var statJin = safeObj(jiyi['津渡']);
    var statZhi = safeObj(jiyi['支汊']);
    if (Object.keys(statJin).length || Object.keys(statZhi).length) {
      return { 津渡: statJin, 支汊: statZhi };
    }
    return computeJiyiFromCatalog(stat);
  }

  function findCatalogEvent(bucket, id) {
    if (!id || !Array.isArray(DWF_JIYI_CATALOG)) return {};
    for (var i = 0; i < DWF_JIYI_CATALOG.length; i += 1) {
      var ev = DWF_JIYI_CATALOG[i] || {};
      if (ev.id === id && (!bucket || ev['类型'] === bucket)) return ev;
    }
    return {};
  }

  var __jiyiCacheKey = '';
