  async function acceptJiyiTask(bucket, id) {
    return persistMvuPatch(function (mvuData) {
      normalizeCurrentTasksOnMvu(mvuData);
      var stat = _.get(mvuData, 'stat_data', {});
      if (taskAcceptBlockReason(stat, bucket)) return false;
      if (taskWasAbandoned(stat, id)) return false;
      if (hasCurrentTask(stat, id)) return false;
      var item = safeObj(_.get(stat, ['风闻录', '机宜', bucket, id]));
      if (!item['因由']) item = safeObj(_.get(computeJiyiFromCatalog(stat), [bucket, id]));
      if (!item['因由']) item = safeObj(findCatalogEvent(bucket, id));
      if (!id || !item['因由']) return false;
      _.set(mvuData, ['stat_data', '任务录', '当前', id], {
        id: id,
        类型: bucket,
        状态: '进行中',
        开始行程: Number(_.get(stat, '世界与剧情.行程', 1)) || 1,
        截止行程: Number(item['截止行程']) || 288,
        因由: item['因由'] || '',
        火急: item['火急'] || 2,
        相关人物: item['相关人物'] || '',
        建议地点: item['建议地点'] || '',
        目标: normalizeTaskGoals(item['目标'], item['选项']),
        演完写入: safeObj(item['演完写入']),
        错过策略: item['错过策略'] || '',
        错过写入: safeObj(item['错过写入']),
      });
      _.unset(mvuData, ['stat_data', '风闻录', '机宜', bucket, id]);
      return true;
    });
  }

  async function completeCurrentTask(id) {
    return persistMvuPatch(function (mvuData) {
      normalizeCurrentTasksOnMvu(mvuData);
      var stat = _.get(mvuData, 'stat_data', {});
      var task = getCurrentTask(stat, id);
      if (!taskCanComplete(stat, id)) return false;
      var history = safeObj(stat['履历']);
      var historyKey = nextHistoryKey(history);
      _.set(mvuData, 'stat_data.履历.' + historyKey, formatLvliRecord(stat, task.id));
      applyTaskDoneWritesMvu(mvuData, task['演完写入']);
      removeCurrentTaskOnMvu(mvuData, task.id);
      return true;
    });
  }

